func CreateBook(ctx context.Context, req *CreateBookRequest) (*Book, error) {
	var b Book
	err := db.QueryRow(ctx, `
		INSERT INTO books (title, author) VALUES ($1, $2)
		RETURNING id, title, author
	`, req.Title, req.Author).Scan(&b.ID, &b.Title, &b.Author)
	if err != nil {
		return nil, err
	}
	return &b, nil
}

type CreateBookRequest struct {
	Title  string `json:"title"`
	Author string `json:"author"`
}

//encore:api public method=GET path=/books
func ListBooks(ctx context.Context) ([]*Book, error) {
	rows, err := db.Query(ctx, `SELECT id, title, author FROM books`)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var books []*Book
	for rows.Next() {
		var b Book
		if err := rows.Scan(&b.ID, &b.Title, &b.Author); err != nil {
			return nil, err
		}
		books = append(books, &b)
	}
	return books, nil
}

